import type { DateString } from '../../../../types/dates.js';

export function getVisibleArrows(
  minMaxBoundaries: {
    min: number | DateString | Date;
    max: number | DateString | Date;
  },
  initialZoom: Date[] | number[] | undefined,
  currentDomain: Date[] | number[] | undefined,
  infiniteZoom: boolean,
) {
  if (!currentDomain && !infiniteZoom) {
    return { left: false, right: false };
  }

  const [initialMin = minMaxBoundaries.min, initialMax = minMaxBoundaries.max] =
    initialZoom || [];
  const [currentMin, currentMax] = currentDomain || [];

  const left = +currentMin > +initialMin || infiniteZoom;
  const right = +currentMax < +initialMax || infiniteZoom;
  return { left, right };
}
